      "path": "src/modules/comments/service.js",
      "content": "const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

let commentsStore = {};

const createComment = (projectId, taskId, message) => {
  const project = projectsService.getProject(projectId);
  if (!project) return null;

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return null;

  const comment = { id: generateId(), message };
  if (!commentsStore[projectId]) commentsStore[projectId] = {};
  if (!commentsStore[projectId][taskId]) commentsStore[projectId][taskId] = [];

  commentsStore[projectId][taskId].push(comment);
  return comment;
};

const getComments = (projectId, taskId) => {
  const project = projectsService.getProject(projectId);
  if (!project) return null;

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return null;

  return commentsStore[projectId] && commentsStore[projectId][taskId] ? commentsStore[projectId][taskId] : [];
};

module.exports = { createComment, getComments };
