      "content": "const { generateId } = require('../../lib/id');

let projectsStore = [];

const createProject = (name) => {
  const project = { id: generateId(), name, members: [], tasks: [] };
  projectsStore.push(project);
  return project;
};

const getAllProjects = () => {
  return projectsStore;
};

const getProject = (projectId) => {
  return projectsStore.find(p => p.id === projectId);
};

module.exports = { createProject, getAllProjects, getProject };
