      "content": "const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Title is required');
  }

  const task = service.createTask(req.params.projectId, title);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }

  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const tasks = service.getTasks(req.params.projectId);
  if (!tasks) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }

  res.json({ tasks });
});

