      "path": "src/modules/tasks/service.js",
      "content": "const projectsService = require('../projects/service');

const createTask = (projectId, title) => {
  const project = projectsService.getProject(projectId);
  if (!project) return null;

  const task = { id: generateId(), title, status: 'pending' };
  project.tasks.push(task);
  return task;
};

const getTasks = (projectId) => {
  const project = projectsService.getProject(projectId);
  if (!project) return null;

  return project.tasks;
};

const updateTask = (projectId, taskId, status) => {
  const project = projectsService.getProject(projectId);
  if (!project) return null;

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return null;

  task.status = status;
  return task;
};

module.exports = { createTask, getTasks, updateTask };
